  if (g < 8.0) return sceneRosette(uv, variant, family);
  if (g < 9.0) return sceneCathedral(uv, variant, family);
  if (g < 10.0) return sceneDomain(uv, variant, family);
  if (g < 11.0) return sceneGrid(uv, variant, family);
  if (g < 12.0) return sceneAurora(uv, variant, family) + sceneForge(uv, variant, family) * 0.3;
  if (g < 13.0) return sceneReaction(uv, variant, family);
  if (g < 14.0) return sceneGyroid(uv, variant, family);
  if (g < 15.0) return sceneMandelbox(uv, variant, family);
  if (g < 16.0) return scenePulseField(uv, variant, family);
  if (g < 17.0) return sceneCellular(uv, variant, family);
